use cardano/transaction.{Transaction, OutputReference}
use cardano/assets
use aiken/collection/list

pub type EscrowDatum {
  buyer: ByteArray,
  seller: ByteArray,
  amount: Int,
  deadline: Int,
}

pub type EscrowRedeemer {
  Claim
  Cancel
}

validator escrow_contract {
  spend(datum: Option<EscrowDatum>, redeemer: EscrowRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Claim -> list.has(self.extra_signatories, d.seller)
      Cancel -> {
        let after_deadline =
          when self.validity_range.lower_bound.bound_type is {
            transaction.Finite(lo) -> lo > d.deadline
            _ -> False
          }
        list.has(self.extra_signatories, d.buyer) && after_deadline
      }
    }
  }
}

use cardano/transaction.{Transaction, OutputReference}
