use aiken/interval

pub type VestingDatum {
  beneficiary: ByteArray,
  lock_until: Int,
}

validator vesting {
  spend(datum: Option<VestingDatum>, _redeemer: Void, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let signed_by_beneficiary = list.has(self.extra_signatories, d.beneficiary)
    let time_passed = interval.is_entirely_after(self.validity_range, d.lock_until)
    signed_by_beneficiary && time_passed
  }
}

use cardano/transaction.{Transaction, OutputReference}
use aiken/collection/list
use aiken/interval

pub type AuctionDatum {
  owner: ByteArray,
  highest_bidder: ByteArray,
  highest_bid: Int,
  auction_end: Int,
}

pub type AuctionRedeemer {
  ClaimLot
  CancelAuction
}

validator auction {
  spend(datum: Option<AuctionDatum>, redeemer: AuctionRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      ClaimLot -> {
        let ended = interval.is_entirely_after(self.validity_range, d.auction_end)
        let signed = list.has(self.extra_signatories, d.highest_bidder)
        ended && signed && d.highest_bid > 0
      }
      CancelAuction -> {
        let signed_owner = list.has(self.extra_signatories, d.owner)
        signed_owner && d.highest_bid == 0
      }
    }
  }
}

