use cardano/transaction.{Transaction, OutputReference}
use cardano/assets
use aiken/collection/list
use aiken/interval

pub type LendingDatum {
  borrower: ByteArray,
  lender: ByteArray,
  repayment_amount: Int,
  repayment_deadline: Int,
}

pub type LendingRedeemer {
  Repay
  Liquidate
}

validator lending {
  spend(datum: Option<LendingDatum>, redeemer: LendingRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> {
        let before_deadline = interval.is_entirely_before(self.validity_range, d.repayment_deadline)
        let signed_borrower = list.has(self.extra_signatories, d.borrower)
        let lender_paid =
          list.any(
            self.outputs,
            fn(output) {
              output.address.payment_credential == cardano/address.from_verification_key(d.lender).payment_credential && assets.lovelace_of(output.value) >= d.repayment_amount
            },
          )
        before_deadline && signed_borrower && lender_paid
      }
      Liquidate -> {
        let after_deadline = interval.is_entirely_after(self.validity_range, d.repayment_deadline)
        let signed_lender = list.has(self.extra_signatories, d.lender)
        after_deadline && signed_lender
      }
    }
  }
}

