pub type MultisigEscrowDatum {
  signers: List<ByteArray>,
  threshold: Int,
  recipient: ByteArray,
  total_locked: Int,
}

pub type MultisigRedeemer {
  Release
  Refund
}

validator multisig_escrow {
  spend(datum: Option<MultisigEscrowDatum>, redeemer: MultisigRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let sig_count =
      list.count(
        d.signers,
        fn(signer) { list.has(self.extra_signatories, signer) },
      )
    when redeemer is {
      Release -> sig_count >= d.threshold
      Refund -> {
        let total_signers = list.length(d.signers)
        sig_count == total_signers
      }
    }
  }
}

