pub type TimeLockedPaymentDatum {
  sender: ByteArray,
  recipient: ByteArray,
  unlock_time: Int,
  amount: Int,
}

pub type TimeLockedRedeemer {
  Collect
  Reclaim
}

validator time_locked_payment {
  spend(datum: Option<TimeLockedPaymentDatum>, redeemer: TimeLockedRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Collect -> {
        let after_unlock = interval.is_entirely_after(self.validity_range, d.unlock_time)
        let signed_recipient = list.has(self.extra_signatories, d.recipient)
        after_unlock && signed_recipient
      }
      Reclaim -> {
        let before_unlock = interval.is_entirely_before(self.validity_range, d.unlock_time)
        let signed_sender = list.has(self.extra_signatories, d.sender)
        before_unlock && signed_sender
      }
    }
  }
}

