use cardano/assets
use cardano/transaction.{Transaction, OutputReference}
use aiken/collection/list

pub type DaoConfig {
  approved_signers: List<ByteArray>,
  quorum: Int,
  token_name: ByteArray,
}

pub type DaoMintRedeemer {
  amount: Int,
  proposal_id: ByteArray,
}

fn count_signers(signers: List<ByteArray>, approved: List<ByteArray>) -> Int {
  list.foldl(
    signers,
    0,
    fn(signer, acc) {
      if list.has(approved, signer) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator dao_token_mint(config: DaoConfig) {
  mint(redeemer: DaoMintRedeemer, policy_id: ByteArray, self: Transaction) -> Bool {
    let signer_count = count_signers(self.extra_signatories, config.approved_signers)
    let quorum_met = signer_count >= config.quorum
    let minted = assets.quantity_of(self.mint, policy_id, config.token_name)
    let correct_amount = minted == redeemer.amount && redeemer.amount > 0
    quorum_met && correct_amount
  }
}

