pub type GovernanceConfig {
  council_members: List<ByteArray>,
  min_council_signers: Int,
  epoch_mint_limit: Int,
  gov_token_name: ByteArray,
}

pub type GovMintRedeemer {
  requested_amount: Int,
  epoch_number: Int,
  justification_hash: ByteArray,
}

fn count_council_signatures(
  extra_signatories: List<ByteArray>,
  council: List<ByteArray>,
) -> Int {
  list.foldl(
    council,
    0,
    fn(member, acc) {
      if list.has(extra_signatories, member) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator governance_token(config: GovernanceConfig) {
  mint(redeemer: GovMintRedeemer, policy_id: ByteArray, self: Transaction) -> Bool {
    let council_sigs =
      count_council_signatures(self.extra_signatories, config.council_members)
    let enough_signers = council_sigs >= config.min_council_signers
    let minted =
      assets.quantity_of(self.mint, policy_id, config.gov_token_name)
    let within_limit = redeemer.requested_amount > 0 && redeemer.requested_amount <= config.epoch_mint_limit
    let correct_mint = minted == redeemer.requested_amount
    enough_signers && within_limit && correct_mint
  }
}

