type MultiSigConfig {
  signer_a: ByteArray,
  signer_b: ByteArray,
  signer_c: ByteArray,
  threshold: Int,
}

fn count_signers(config: MultiSigConfig, signatories: List<ByteArray>) -> Int {
  let a_signed =
    if list.has(signatories, config.signer_a) {
      1
    } else {
      0
    }
  let b_signed =
    if list.has(signatories, config.signer_b) {
      1
    } else {
      0
    }
  let c_signed =
    if list.has(signatories, config.signer_c) {
      1
    } else {
      0
    }
  a_signed + b_signed + c_signed
}

validator multisig_stake_control(config: MultiSigConfig) {
  publish(certificate: Certificate, _redeemer: Data, self: Transaction) -> Bool {
    let signer_count = count_signers(config, self.extra_signatories)
    when certificate is {
      RegisterCredential { .. } -> signer_count >= config.threshold
      UnregisterCredential { .. } -> signer_count >= config.threshold
      _ -> False
    }
  }
}

