type CrossProtocolConfig {
  primary_admin: ByteArray,
  secondary_admin: ByteArray,
  protocol_id: ByteArray,
  require_dual_sign_for_unregister: Bool,
}

validator cross_protocol_credential(config: CrossProtocolConfig) {
  publish(certificate: Certificate, _redeemer: Data, self: Transaction) -> Bool {
    let primary_signed =
      list.has(self.extra_signatories, config.primary_admin)
    let secondary_signed =
      list.has(self.extra_signatories, config.secondary_admin)
    let dual_signed = primary_signed && secondary_signed
    when certificate is {
      RegisterCredential { .. } -> primary_signed
      UnregisterCredential { .. } ->
        if config.require_dual_sign_for_unregister {
          dual_signed
        } else {
          primary_signed
        }
      DelegateCredential { .. } -> primary_signed || secondary_signed
      RegisterAndDelegateCredential { .. } -> dual_signed
      _ -> False
    }
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction, OutputReference, InlineDatum}

pub type OracleData {
  price_numerator: Int,
  price_denominator: Int,
  asset_policy: ByteArray,
  asset_name: ByteArray,
}

pub type SwapRedeemer {
  oracle_ref: OutputReference,
  min_output_lovelace: Int,
}

validator price_oracle_swap {
  spend(datum: Option<Data>, redeemer: SwapRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    let oracle_input =
      list.find(
        self.reference_inputs,
        fn(ref_in) { ref_in.output_reference == redeemer.oracle_ref },
      )
    expect Some(oracle_ref_input) = oracle_input
    expect InlineDatum(raw) = oracle_ref_input.output.datum
    expect oracle: OracleData = raw
    expect Some(own_input) = transaction.find_input(self.inputs, own_ref)
    let input_tokens =
      assets.quantity_of(
        own_input.output.value,
        oracle.asset_policy,
        oracle.asset_name,
      )
    let expected_lovelace =
      input_tokens * oracle.price_numerator / oracle.price_denominator
    redeemer.min_output_lovelace >= expected_lovelace
  }
}

use aiken/collection/list
