use cardano/transaction.{Transaction, OutputReference, InlineDatum}

pub type ProtocolConfig {
  min_fee_lovelace: Int,
  treasury_address_hash: ByteArray,
  admin_key: ByteArray,
}

pub type ConfigRedeemer {
  config_ref: OutputReference,
}

validator protocol_fee_check {
  spend(datum: Option<Data>, redeemer: ConfigRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    let config_input =
      list.find(
        self.reference_inputs,
        fn(ref_in) { ref_in.output_reference == redeemer.config_ref },
      )
    expect Some(config_ref_input) = config_input
    expect InlineDatum(raw) = config_ref_input.output.datum
    expect config: ProtocolConfig = raw
    let fee_paid =
      list.any(
        self.outputs,
        fn(output) {
          when output.address.payment_credential is {
            cardano/address.VerificationKey(hash) ->
              hash == config.treasury_address_hash && assets.lovelace_of(
                output.value,
              ) >= config.min_fee_lovelace
            _ -> False
          }
        },
      )
    fee_paid
  }
}

