pub type ExchangeRate {
  from_policy: ByteArray,
  from_name: ByteArray,
  to_policy: ByteArray,
  to_name: ByteArray,
  rate_numerator: Int,
  rate_denominator: Int,
}

pub type ExchangeRedeemer {
  rate_ref: OutputReference,
  input_amount: Int,
}

validator exchange_rate_validator {
  spend(datum: Option<Data>, redeemer: ExchangeRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    let rate_input =
      list.find(
        self.reference_inputs,
        fn(ref_in) { ref_in.output_reference == redeemer.rate_ref },
      )
    expect Some(rate_ref_input) = rate_input
    expect InlineDatum(raw) = rate_ref_input.output.datum
    expect rate: ExchangeRate = raw
    let expected_output =
      redeemer.input_amount * rate.rate_numerator / rate.rate_denominator
    let has_correct_output =
      list.any(
        self.outputs,
        fn(output) {
          assets.quantity_of(output.value, rate.to_policy, rate.to_name) >= expected_output
        },
      )
    has_correct_output
  }
}

