  reward_token_policy: ByteArray,
  reward_token_name: ByteArray,
  beneficiary: ByteArray,
}

pub type RewardRedeemer {
  schedule_ref: OutputReference,
  epochs_claimed: Int,
}

validator reward_schedule_validator {
  spend(datum: Option<Data>, redeemer: RewardRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    let schedule_input =
      list.find(
        self.reference_inputs,
        fn(ref_in) { ref_in.output_reference == redeemer.schedule_ref },
      )
    expect Some(sched_ref_input) = schedule_input
    expect InlineDatum(raw) = sched_ref_input.output.datum
    expect schedule: RewardSchedule = raw
    let expected_reward = schedule.reward_per_epoch * redeemer.epochs_claimed
    let beneficiary_receives =
      list.any(
        self.outputs,
        fn(output) {
          when output.address.payment_credential is {
