pub type DexPriceFeed {
  token_a_policy: ByteArray,
  token_a_name: ByteArray,
  token_b_policy: ByteArray,
  token_b_name: ByteArray,
  reserve_a: Int,
  reserve_b: Int,
}

pub type TradeDatum {
  trader: ByteArray,
  sell_amount: Int,
  min_buy_amount: Int,
}

pub type DexRedeemer {
  price_feed_ref: OutputReference,
}

validator dex_price_feed_validator {
  spend(datum: Option<TradeDatum>, redeemer: DexRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    let feed_input =
      list.find(
        self.reference_inputs,
        fn(ref_in) { ref_in.output_reference == redeemer.price_feed_ref },
      )
    expect Some(feed_ref_input) = feed_input
    expect InlineDatum(raw) = feed_ref_input.output.datum
    expect feed: DexPriceFeed = raw
    expect Some(trade) = datum
    let output_amount =
      trade.sell_amount * feed.reserve_b / ( feed.reserve_a + trade.sell_amount )
    let price_acceptable = output_amount >= trade.min_buy_amount
    let trader_signed = list.has(self.extra_signatories, trade.trader)
    let trader_receives =
      list.any(
        self.outputs,
        fn(output) {
          assets.quantity_of(
            output.value,
            feed.token_b_policy,
            feed.token_b_name,
          ) >= trade.min_buy_amount
        },
      )
    price_acceptable && trader_signed && trader_receives
  }
}

