use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction, OutputReference}
use aiken/collection/list

pub type NftRedeemer {
  utxo_ref: OutputReference,
  token_name: ByteArray,
}

validator nft_policy {
  mint(redeemer: NftRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let must_consume_utxo =
      list.any(
        self.inputs,
        fn(input) { input.output_reference == redeemer.utxo_ref },
      )
    let must_mint_exactly_one =
      assets.quantity_of(self.mint, policy_id, redeemer.token_name) == 1
    must_consume_utxo && must_mint_exactly_one
  }
}

use cardano/assets.{PolicyId}
