pub type CappedMintRedeemer {
  mint_amount: Int,
  asset_name: ByteArray,
}

validator capped_supply_policy(admin_key: ByteArray, max_supply: Int) {
  mint(redeemer: CappedMintRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let signed_by_admin = list.has(self.extra_signatories, admin_key)
    let minted_qty =
      assets.quantity_of(self.mint, policy_id, redeemer.asset_name)
    let valid_amount = minted_qty == redeemer.mint_amount
    let within_cap = redeemer.mint_amount > 0 && redeemer.mint_amount <= max_supply
    signed_by_admin && valid_amount && within_cap
  }
}

