use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction, OutputReference}
use aiken/collection/list

pub type BondingCurveRedeemer {
  payment_utxo: OutputReference,
  mint_amount: Int,
  current_supply: Int,
  token_name: ByteArray,
}

validator bonding_curve_policy(treasury_address: ByteArray, base_price: Int) {
  mint(redeemer: BondingCurveRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let price_per_token = base_price + redeemer.current_supply * base_price / 100
    let total_cost = price_per_token * redeemer.mint_amount
    let payment_made =
      list.any(
        self.outputs,
        fn(output) {
          output.address.payment_credential == cardano/address.Script(treasury_address) && assets.lovelace_of(
            output.value,
          ) >= total_cost
        },
      )
    let consumed_utxo =
      list.any(
        self.inputs,
        fn(input) { input.output_reference == redeemer.payment_utxo },
      )
    let correct_mint =
      assets.quantity_of(self.mint, policy_id, redeemer.token_name) == redeemer.mint_amount
    let positive_amount = redeemer.mint_amount > 0
    consumed_utxo && correct_mint && positive_amount && payment_made
  }
}

use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}
use aiken/collection/list

pub type ProtocolFeeRedeemer {
  epoch_number: Int,
  fee_amount: Int,
  token_name: ByteArray,
}

validator protocol_fee_policy(admin_key: ByteArray, max_fee_per_epoch: Int) {
  mint(redeemer: ProtocolFeeRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let signed_by_admin = list.has(self.extra_signatories, admin_key)
    let valid_fee =
      redeemer.fee_amount > 0 && redeemer.fee_amount <= max_fee_per_epoch
    let correct_mint =
      assets.quantity_of(self.mint, policy_id, redeemer.token_name) == redeemer.fee_amount
    let valid_epoch = redeemer.epoch_number >= 0
    signed_by_admin && valid_fee && correct_mint && valid_epoch
  }
}

use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction, OutputReference}
use aiken/collection/list

pub type RewardTier {
  Bronze
  Silver
  Gold
}

pub type LoyaltyRedeemer {
  customer_key: ByteArray,
  purchase_utxo: OutputReference,
  tier: RewardTier,
  token_name: ByteArray,
}

fn tier_amount(tier: RewardTier) -> Int {
  when tier is {
    Bronze -> 10
    Silver -> 50
    Gold -> 200
  }
}

validator loyalty_reward_policy(merchant_key: ByteArray) {
  mint(redeemer: LoyaltyRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let signed_by_merchant = list.has(self.extra_signatories, merchant_key)
    let signed_by_customer =
      list.has(self.extra_signatories, redeemer.customer_key)
    let consumed_purchase =
      list.any(
        self.inputs,
        fn(input) { input.output_reference == redeemer.purchase_utxo },
      )
    let expected_amount = tier_amount(redeemer.tier)
    let correct_mint =
      assets.quantity_of(self.mint, policy_id, redeemer.token_name) == expected_amount
    signed_by_merchant && signed_by_customer && consumed_purchase && correct_mint
  }
}

use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}
use aiken/collection/list

pub type BridgeRedeemer {
  bridge_proof_hash: ByteArray,
  destination_key: ByteArray,
  bridge_amount: Int,
  token_name: ByteArray,
  validator_keys: List<ByteArray>,
}

validator bridge_token_policy(min_validators: Int) {
  mint(redeemer: BridgeRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let validator_signatures =
      list.count(
        redeemer.validator_keys,
        fn(vk) { list.has(self.extra_signatories, vk) },
      )
    let enough_validators = validator_signatures >= min_validators
    let positive_amount = redeemer.bridge_amount > 0
    let correct_mint =
      assets.quantity_of(self.mint, policy_id, redeemer.token_name) == redeemer.bridge_amount
    let valid_proof =
      builtin.length_of_bytearray(redeemer.bridge_proof_hash) == 32
    enough_validators && positive_amount && correct_mint && valid_proof
  }
}

