}

pub type MultiSigRedeemer {
  Spend
}

validator multisig_2of3 {
  spend(datum: Option<MultiSigDatum>, _redeemer: MultiSigRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let sig1 = list.has(self.extra_signatories, d.admin1)
    let sig2 = list.has(self.extra_signatories, d.admin2)
    let sig3 = list.has(self.extra_signatories, d.admin3)
    let sig_count =
      if sig1 { 1 } else { 0 }
      + if sig2 { 1 } else { 0 }
      + if sig3 { 1 } else { 0 }
    sig_count >= 2
  }
}

