}

validator weighted_vote {
  spend(datum: Option<WeightedDatum>, _redeemer: WeightedRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let w1 =
      if list.has(self.extra_signatories, d.member_high) {
        d.weight_high
      } else {
        0
      }
    let w2 =
      if list.has(self.extra_signatories, d.member_mid) {
        d.weight_mid
      } else {
        0
      }
    let w3 =
      if list.has(self.extra_signatories, d.member_low) {
        d.weight_low
      } else {
        0
      }
    w1 + w2 + w3 >= d.threshold
  }
}

