pub type CouncilDatum {
  member1: VerificationKeyHash,
  member2: VerificationKeyHash,
  member3: VerificationKeyHash,
  member4: VerificationKeyHash,
  member5: VerificationKeyHash,
  required: Int,
}

pub type CouncilRedeemer {
  Approve
}

fn count_sigs(signatories: List<VerificationKeyHash>, members: List<VerificationKeyHash>) -> Int {
  list.foldl(
    members,
    0,
    fn(member, acc) {
      if list.has(signatories, member) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator council_approval {
  spend(datum: Option<CouncilDatum>, _redeemer: CouncilRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let members =
      [d.member1, d.member2, d.member3, d.member4, d.member5]
    let sig_count = count_sigs(self.extra_signatories, members)
    sig_count >= d.required
  }
}

