use cardano/transaction.{Transaction, OutputReference, InlineDatum}
use cardano/assets
use aiken/collection/list

pub type TreasuryDatum {
  treasurer: VerificationKeyHash,
  cosigner1: VerificationKeyHash,
  cosigner2: VerificationKeyHash,
  min_reserve: Int,
}

pub type TreasuryRedeemer {
  Withdraw
}

validator treasury_multisig {
  spend(datum: Option<TreasuryDatum>, _redeemer: TreasuryRedeemer, own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let treasurer_signed = list.has(self.extra_signatories, d.treasurer)
    let co1_signed = list.has(self.extra_signatories, d.cosigner1)
    let co2_signed = list.has(self.extra_signatories, d.cosigner2)
    let auth_ok = treasurer_signed && (co1_signed || co2_signed)
    expect Some(own_input) = transaction.find_input(self.inputs, own_ref)
    let script_address = own_input.output.address
    let continuing_outputs =
      list.filter(
        self.outputs,
        fn(output) { output.address == script_address },
      )
    let reserve_ok =
      list.any(
        continuing_outputs,
        fn(output) {
          expect InlineDatum(raw) = output.datum
          expect cont_datum: TreasuryDatum = raw
          cont_datum.treasurer == d.treasurer && cont_datum.cosigner1 == d.cosigner1 && cont_datum.cosigner2 == d.cosigner2 && assets.lovelace_of(output.value) >= d.min_reserve
        },
      )
    auth_ok && reserve_ok
  }
}

