pub type LoanDatum {
  borrower: ByteArray,
  collateral_amount: Int,
  loan_amount: Int,
  liquidation_threshold: Int,
}

pub type OracleDatum {
  price_numerator: Int,
  price_denominator: Int,
  last_updated: Int,
}

pub type LiquidationRedeemer {
  Liquidate { oracle_ref: OutputReference }
  Repay
}

validator defi_liquidation {
  spend(datum: Option<LoanDatum>, redeemer: LiquidationRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(loan) = datum
    when redeemer is {
      Liquidate { oracle_ref } -> {
        expect Some(oracle_input) = transaction.find_input(self.reference_inputs, oracle_ref)
        expect InlineDatum(raw_oracle) = oracle_input.output.datum
        expect oracle: OracleDatum = raw_oracle
        let collateral_value = loan.collateral_amount * oracle.price_numerator / oracle.price_denominator
        let ratio = collateral_value * 100 / loan.loan_amount
        let is_undercollateralized = ratio < loan.liquidation_threshold
        let valid_time = interval.is_entirely_after(self.validity_range, oracle.last_updated)
        is_undercollateralized && valid_time
      }
      Repay -> list.has(self.extra_signatories, loan.borrower)
    }
  }
}

