pub type ProposalDatum {
  proposal_id: Int,
  creator: ByteArray,
  vote_start: Int,
  vote_end: Int,
  yes_votes: Int,
  no_votes: Int,
}

pub type VoteRedeemer {
  VoteYes { voter: ByteArray }
  VoteNo { voter: ByteArray }
}

validator dao_governance {
  spend(datum: Option<ProposalDatum>, redeemer: VoteRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(proposal) = datum
    let within_voting_period = interval.is_entirely_after(self.validity_range, proposal.vote_start) && interval.is_entirely_before(self.validity_range, proposal.vote_end)
    when redeemer is {
      VoteYes { voter } -> {
        let signed = list.has(self.extra_signatories, voter)
        within_voting_period && signed
      }
      VoteNo { voter } -> {
        let signed = list.has(self.extra_signatories, voter)
        within_voting_period && signed
      }
    }
  }

  publish(redeemer: Int, certificate: Certificate, self: Transaction) -> Bool {
    when certificate is {
      RegisterCredential { .. } -> redeemer == 0
      DelegateCredential { .. } -> {
        list.length(self.extra_signatories) > 0
      }
      _ -> False
    }
  }
}

