}

pub type MarketRedeemer {
  Buy
  Cancel
}

pub type MintAction {
  MintReceipt
  BurnReceipt
}

fn seller_paid(self: Transaction, seller: ByteArray, price: Int) -> Bool {
  list.any(
    self.outputs,
    fn(output) {
      when output.address.payment_credential is {
        cardano/address.VerificationKey(hash) ->
          hash == seller && assets.lovelace_of(output.value) >= price
        _ -> False
      }
    },
  )
}

validator nft_marketplace {
  spend(datum: Option<ListingDatum>, redeemer: MarketRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(listing) = datum
    when redeemer is {
      Buy -> seller_paid(self, listing.seller, listing.price_lovelace)
      Cancel -> list.has(self.extra_signatories, listing.seller)
    }
  }

  mint(redeemer: MintAction, _policy_id: ByteArray, self: Transaction) -> Bool {
    when redeemer is {
      MintReceipt -> list.length(self.extra_signatories) > 0
      BurnReceipt -> True
    }
  }
}

