use cardano/certificate.{Certificate, RegisterCredential, UnregisterCredential, DelegateCredential, RegisterAndDelegateCredential}

pub type StakingConfig {
  admin: ByteArray,
  min_stake_period: Int,
  pool_id: ByteArray,
}

pub type WithdrawRedeemer {
  ClaimRewards
  EmergencyWithdraw
}

validator staking_dashboard(config: StakingConfig) {
  withdraw(redeemer: WithdrawRedeemer, _account: ByteArray, self: Transaction) -> Bool {
    when redeemer is {
      ClaimRewards -> {
        let is_after_min_period = interval.is_entirely_after(self.validity_range, config.min_stake_period)
        let signed_by_admin = list.has(self.extra_signatories, config.admin)
        is_after_min_period || signed_by_admin
      }
      EmergencyWithdraw -> list.has(self.extra_signatories, config.admin)
    }
  }

  publish(redeemer: Int, certificate: Certificate, self: Transaction) -> Bool {
    let admin_signed = list.has(self.extra_signatories, config.admin)
    when certificate is {
      RegisterCredential { .. } -> admin_signed && redeemer == 1
      UnregisterCredential { .. } -> admin_signed && redeemer == 2
      DelegateCredential { .. } -> admin_signed && redeemer == 3
      RegisterAndDelegateCredential { .. } -> admin_signed && redeemer == 4
      _ -> False
    }
  }
}

