pub type FarmDatum {
  farmer: ByteArray,
  staked_amount: Int,
  stake_timestamp: Int,
}

pub type PoolDatum {
  reward_rate_per_epoch: Int,
  epoch_length: Int,
  total_staked: Int,
}

pub type FarmRedeemer {
  Harvest { pool_ref: OutputReference }
  Unstake
}

validator yield_farm {
  spend(datum: Option<FarmDatum>, redeemer: FarmRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(farm) = datum
    when redeemer is {
      Harvest { pool_ref } -> {
        expect Some(pool_input) = transaction.find_input(self.reference_inputs, pool_ref)
        expect InlineDatum(raw_pool) = pool_input.output.datum
        expect pool: PoolDatum = raw_pool
        let is_valid_time = interval.is_entirely_after(self.validity_range, farm.stake_timestamp + pool.epoch_length)
        let signed = list.has(self.extra_signatories, farm.farmer)
        let expected_reward = farm.staked_amount * pool.reward_rate_per_epoch / pool.total_staked
        let has_reward_output = list.any(
          self.outputs,
          fn(o) { assets.lovelace_of(o.value) >= expected_reward },
        )
        is_valid_time && signed && has_reward_output
      }
      Unstake -> list.has(self.extra_signatories, farm.farmer)
    }
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction, OutputReference, InlineDatum}

pub type SwapDatum {
  user: ByteArray,
  input_policy: ByteArray,
  input_asset: ByteArray,
  input_amount: Int,
  min_output_amount: Int,
}

pub type PriceDatum {
  numerator: Int,
  denominator: Int,
}

pub type SwapRedeemer {
  ExecuteSwap { oracle_ref: OutputReference, output_policy: ByteArray, output_asset: ByteArray }
  CancelSwap
}

validator dex_swap {
  spend(datum: Option<SwapDatum>, redeemer: SwapRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(swap) = datum
    when redeemer is {
      ExecuteSwap { oracle_ref, output_policy, output_asset } -> {
        expect Some(oracle_input) = transaction.find_input(self.reference_inputs, oracle_ref)
        expect InlineDatum(raw_price) = oracle_input.output.datum
        expect price: PriceDatum = raw_price
        let expected_output = swap.input_amount * price.numerator / price.denominator
        let meets_slippage = expected_output >= swap.min_output_amount
        let user_receives = list.any(
          self.outputs,
          fn(o) {
            assets.quantity_of(o.value, output_policy, output_asset) >= swap.min_output_amount
          },
        )
        let signed = list.has(self.extra_signatories, swap.user)
        meets_slippage && user_receives && signed
      }
      CancelSwap -> list.has(self.extra_signatories, swap.user)
    }
  }
}

use aiken/interval
use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction, OutputReference, InlineDatum}

pub type BondDatum {
  issuer: ByteArray,
  holder: ByteArray,
  face_value: Int,
  coupon_rate: Int,
  maturity_time: Int,
}

pub type MultisigConfig {
  signers: List<ByteArray>,
  required: Int,
}

pub type BondRedeemer {
  Redeem
  TransferBond { new_holder: ByteArray }
  EarlyLiquidation
}

fn count_signatures(signatories: List<ByteArray>, required_signers: List<ByteArray>) -> Int {
  list.foldl(
    required_signers,
    0,
    fn(signer, acc) {
      if list.has(signatories, signer) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator bond_protocol(multisig: MultisigConfig) {
  spend(datum: Option<BondDatum>, redeemer: BondRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(bond) = datum
    when redeemer is {
      Redeem -> {
        let is_mature = interval.is_entirely_after(self.validity_range, bond.maturity_time)
        let holder_signed = list.has(self.extra_signatories, bond.holder)
        let payout = bond.face_value + bond.face_value * bond.coupon_rate / 100
        let has_payout = list.any(
          self.outputs,
          fn(o) { assets.lovelace_of(o.value) >= payout },
        )
        is_mature && holder_signed && has_payout
      }
      TransferBond { new_holder } -> {
        let holder_signed = list.has(self.extra_signatories, bond.holder)
        let has_continuing_output = list.any(
          self.outputs,
          fn(o) {
            when o.datum is {
              InlineDatum(raw) -> {
                expect new_bond: BondDatum = raw
                new_bond.holder == new_holder && new_bond.face_value == bond.face_value
              }
              _ -> False
            }
          },
        )
        holder_signed && has_continuing_output
      }
      EarlyLiquidation -> {
        let sig_count = count_signatures(self.extra_signatories, multisig.signers)
        sig_count >= multisig.required
      }
    }
  }
}

use aiken/interval
use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference, InlineDatum}
use cardano/certificate.{Certificate, RegisterCredential, UnregisterCredential}

pub type GovernanceDatum {
  proposal_hash: ByteArray,
  voting_start: Int,
  voting_end: Int,
  quorum: Int,
  current_votes: Int,
  approved: Bool,
}

pub type GovRedeemer {
  CastVote { voter: ByteArray, support: Bool }
  FinalizeProposal
}

validator governance_system {
  spend(datum: Option<GovernanceDatum>, redeemer: GovRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(gov) = datum
    when redeemer is {
      CastVote { voter, support } -> {
        let in_period = interval.is_entirely_after(self.validity_range, gov.voting_start) && interval.is_entirely_before(self.validity_range, gov.voting_end)
        let signed = list.has(self.extra_signatories, voter)
        let has_updated_output = list.any(
          self.outputs,
          fn(o) {
            when o.datum is {
              InlineDatum(raw) -> {
                expect updated: GovernanceDatum = raw
                if support {
                  updated.current_votes == gov.current_votes + 1
                } else {
                  updated.current_votes == gov.current_votes
                }
              }
              _ -> False
            }
          },
        )
        in_period && signed && has_updated_output
      }
      FinalizeProposal -> {
        let past_end = interval.is_entirely_after(self.validity_range, gov.voting_end)
        let met_quorum = gov.current_votes >= gov.quorum
        past_end && met_quorum
      }
    }
  }

  publish(_redeemer: Int, certificate: Certificate, self: Transaction) -> Bool {
    when certificate is {
      RegisterCredential { .. } -> list.length(self.extra_signatories) > 0
      UnregisterCredential { .. } -> list.length(self.extra_signatories) > 0
      _ -> False
    }
  }
}

