  finality_reached: Bool,
}

pub type BridgeRedeemer {
  Release { oracle_ref: OutputReference }
  Refund
  EmergencyOverride
}

fn count_guardian_sigs(extra_sigs: List<ByteArray>, guardians: List<ByteArray>) -> Int {
  list.foldl(
    guardians,
    0,
    fn(g, acc) {
      if list.has(extra_sigs, g) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator bridge_escrow {
  spend(datum: Option<EscrowDatum>, redeemer: BridgeRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(escrow) = datum
    when redeemer is {
      Release { oracle_ref } -> {
        expect Some(oracle_input) = transaction.find_input(self.reference_inputs, oracle_ref)
        expect InlineDatum(raw_oracle) = oracle_input.output.datum
        expect oracle: BridgeOracleDatum = raw_oracle
        let tx_confirmed = oracle.confirmed_tx == escrow.source_chain_tx && oracle.finality_reached
        let time_lock_passed = interval.is_entirely_after(self.validity_range, escrow.lock_until)
        let guardian_count = count_guardian_sigs(self.extra_signatories, escrow.guardians)
        let enough_confirmations = guardian_count >= escrow.required_confirmations
        let recipient_paid = list.any(
          self.outputs,
          fn(o) { assets.lovelace_of(o.value) >= escrow.amount },
        )
        tx_confirmed && time_lock_passed && enough_confirmations && recipient_paid
      }
      Refund -> {
        let guardian_count = count_guardian_sigs(self.extra_signatories, escrow.guardians)
        guardian_count >= escrow.required_confirmations
      }
      EmergencyOverride -> {
        let all_signed = list.all(
          escrow.guardians,
          fn(g) { list.has(self.extra_signatories, g) },
        )
        all_signed
      }
    }
  }
}

use aiken/interval
use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction, OutputReference, InlineDatum}

pub type LendingDatum {
  borrower: ByteArray,
  lender: ByteArray,
  principal: Int,
  interest_rate_bps: Int,
  collateral_policy: ByteArray,
  collateral_asset: ByteArray,
  collateral_amount: Int,
  due_date: Int,
  ltv_threshold_pct: Int,
}

pub type PriceOracleDatum {
  collateral_price_num: Int,
  collateral_price_den: Int,
  valid_until: Int,
}

pub type LendingRedeemer {
  Repay
  Liquidate { oracle_ref: OutputReference }
  ClaimExpired
}

validator lending_protocol {
  spend(datum: Option<LendingDatum>, redeemer: LendingRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(loan) = datum
    when redeemer is {
      Repay -> {
        let borrower_signed = list.has(self.extra_signatories, loan.borrower)
        let not_expired = interval.is_entirely_before(self.validity_range, loan.due_date)
        let repay_amount = loan.principal + loan.principal * loan.interest_rate_bps / 10000
        let lender_paid = list.any(
          self.outputs,
          fn(o) { assets.lovelace_of(o.value) >= repay_amount },
        )
        let collateral_returned = list.any(
          self.outputs,
          fn(o) {
            assets.quantity_of(o.value, loan.collateral_policy, loan.collateral_asset) >= loan.collateral_amount
          },
        )
        borrower_signed && not_expired && lender_paid && collateral_returned
      }
      Liquidate { oracle_ref } -> {
        expect Some(oracle_input) = transaction.find_input(self.reference_inputs, oracle_ref)
        expect InlineDatum(raw_price) = oracle_input.output.datum
        expect price: PriceOracleDatum = raw_price
        let oracle_fresh = interval.is_entirely_before(self.validity_range, price.valid_until)
        let collateral_value = loan.collateral_amount * price.collateral_price_num / price.collateral_price_den
        let current_ltv = loan.principal * 100 / collateral_value
        let is_undercollateralized = current_ltv > loan.ltv_threshold_pct
        let lender_signed = list.has(self.extra_signatories, loan.lender)
        oracle_fresh && is_undercollateralized && lender_signed
      }
      ClaimExpired -> {
        let past_due = interval.is_entirely_after(self.validity_range, loan.due_date)
        let lender_signed = list.has(self.extra_signatories, loan.lender)
        past_due && lender_signed
      }
    }
  }
}
